// // This module implements a 5-bit Johnson counter with asynchronous reset and outputs the complement of the last bit on the first bit.
module johnson_counter(
    input clk,
    input reset,
    output reg [4:0] q
);always @(posedge clk) begin
    if (reset)
        q <= 5'b00000;
    else
        q <= {q[3:0], ~q[4]};
end

endmodule
